class Solution {
    /**
     * Finds the smallest stable index i, where unstable_value(i) <= k.
     * unstable_value(i) = max(nums[0..i]) - min(nums[i..n-1])
     *
     * @param nums The input array.
     * @param k The threshold value.
     * @return The smallest stable index, or -1 if none exists.
     */
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        if (n == 0) {
            return -1;
        }

        // 1. Precompute LMax[i] = max(nums[0..i])
        long[] lMax = new long[n];
        lMax[0] = nums[0];
        for (int i = 1; i < n; i++) {
            lMax[i] = Math.max(lMax[i - 1], nums[i]);
        }

        // 2. Precompute RMin[i] = min(nums[i..n-1])
        long[] rMin = new long[n];
        rMin[n - 1] = nums[n - 1];
        for (int i = n - 2; i >= 0; i--) {
            rMin[i] = Math.min(rMin[i + 1], nums[i]);
        }

        // 3. Check stability for each index i
        for (int i = 0; i < n; i++) {
            // Unstable value U_i = LMax[i] - RMin[i]
            long unstableValue = lMax[i] - rMin[i];

            if (unstableValue <= k) {
                // Since we iterate in increasing order, this is the smallest stable index
                return (long) i;
            }
        }

        // 4. If no stable index is found
        return -1L;
    }
}
